package cli

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"syscall"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
	"github.com/spf13/cobra"
)

func openCmd() *cobra.Command {
	var useTmux bool
	var noTmux bool
	var noAgent bool

	cmd := &cobra.Command{
		Use:   "open [feature] [branch]",
		Short: "Open worktree and run agent",
		Long:  "Open a worktree and run the configured agent. With no args, shows an interactive picker.",
		Args:  cobra.RangeArgs(0, 2),
		ValidArgsFunction: func(cmd *cobra.Command, args []string, toComplete string) ([]string, cobra.ShellCompDirective) {
			switch len(args) {
			case 0:
				return internal.ListFeatures(), cobra.ShellCompDirectiveNoFileComp
			case 1:
				return internal.ListBranches(args[0]), cobra.ShellCompDirectiveNoFileComp
			default:
				return nil, cobra.ShellCompDirectiveNoFileComp
			}
		},
		Run: func(cmd *cobra.Command, args []string) {
			feature, branch, err := resolveOpenArgs(args)
			if err != nil {
				fmt.Println(err)
				os.Exit(1)
			}

			path := internal.WorktreePath(feature, branch)

			if _, err := os.Stat(path); os.IsNotExist(err) {
				fmt.Printf("Worktree not found: %s\n", path)
				os.Exit(1)
			}

			if noAgent {
				fmt.Printf("cd %s\n", path)
				fmt.Println("Run your agent manually from there.")
				return
			}

			// Resolve tmux preference
			tmux := useTmux
			if !cmd.Flags().Changed("tmux") && !noTmux {
				cfg := internal.LoadConfig()
				if cfg.UseTmux != nil {
					tmux = *cfg.UseTmux
				}
			}
			if noTmux {
				tmux = false
			}

			if tmux {
				openWithTmux(feature, branch, path)
			} else {
				openDirect(path)
			}
		},
	}

	cmd.Flags().BoolVar(&useTmux, "tmux", false, "Wrap in tmux session")
	cmd.Flags().BoolVar(&noTmux, "no-tmux", false, "Skip tmux even if configured")
	cmd.Flags().BoolVar(&noAgent, "no-agent", false, "Just print the worktree path")

	return cmd
}

func resolveOpenArgs(args []string) (string, string, error) {
	var feature, branch string
	var err error

	switch len(args) {
	case 2:
		return args[0], args[1], nil
	case 1:
		feature = args[0]
		branches := internal.ListBranches(feature)
		if len(branches) == 0 {
			return "", "", fmt.Errorf("no branches found for feature: %s", feature)
		}
		branch, err = pick("Select branch:", branches)
		if err != nil {
			return "", "", err
		}
		return feature, branch, nil
	case 0:
		features := internal.ListFeatures()
		if len(features) == 0 {
			return "", "", fmt.Errorf("no features found. Use 'tws add <feature>' to create one")
		}
		feature, err = pick("Select feature:", features)
		if err != nil {
			return "", "", err
		}
		branches := internal.ListBranches(feature)
		if len(branches) == 0 {
			return "", "", fmt.Errorf("no branches found for feature: %s", feature)
		}
		branch, err = pick("Select branch:", branches)
		if err != nil {
			return "", "", err
		}
		return feature, branch, nil
	}
	return "", "", fmt.Errorf("unexpected args")
}

func openDirect(path string) {
	cfg := internal.LoadConfig()
	agentCmd := cfg.GetAgentCommand()

	if isClaudeAgent(agentCmd) && hasClaudeSession(path) {
		agentCmd = agentCmd + " -c"
	}

	parts := strings.Fields(agentCmd)
	binary, err := exec.LookPath(parts[0])
	if err != nil {
		fmt.Printf("Error: agent %q not found in PATH\n", parts[0])
		os.Exit(1)
	}

	fmt.Printf("Opening: %s\nRunning: %s\n", path, agentCmd)

	if err := os.Chdir(path); err != nil {
		fmt.Printf("Error: could not cd to %s: %v\n", path, err)
		os.Exit(1)
	}

	if err := syscall.Exec(binary, parts, os.Environ()); err != nil {
		fmt.Printf("Error: could not exec %s: %v\n", agentCmd, err)
		os.Exit(1)
	}
}

func openWithTmux(feature, branch, path string) {
	internal.RequireTool("tmux")

	session := sanitizeSessionName(feature + "/" + branch)

	if sessionExists(session) {
		fmt.Printf("Attaching to existing session: %s\n", session)
		internal.Must(internal.Run("tmux", "attach", "-t", session))
		return
	}

	cfg := internal.LoadConfig()
	agentCmd := cfg.GetAgentCommand()

	if isClaudeAgent(agentCmd) && hasClaudeSession(path) {
		agentCmd = agentCmd + " -c"
	}

	fmt.Printf("Creating tmux session: %s\n", session)
	internal.Must(internal.Run("tmux", "new-session", "-d", "-s", session, "-c", path))

	fmt.Printf("Running: %s\n", agentCmd)
	internal.Must(internal.Run("tmux", "send-keys", "-t", session, agentCmd, "Enter"))

	internal.Must(internal.Run("tmux", "attach", "-t", session))
}

func sessionExists(name string) bool {
	cmd := exec.Command("tmux", "has-session", "-t", name)
	err := cmd.Run()
	return err == nil
}

func sanitizeSessionName(s string) string {
	r := strings.NewReplacer(".", "_", ":", "_", "/", "-")
	return r.Replace(s)
}

func isClaudeAgent(cmd string) bool {
	base := strings.Fields(cmd)[0]
	return base == "claude" || base == "claude-dev" || base == "cc"
}

func hasClaudeSession(workdir string) bool {
	home, err := os.UserHomeDir()
	if err != nil {
		return false
	}

	absPath, err := filepath.Abs(workdir)
	if err != nil {
		return false
	}

	encoded := strings.ReplaceAll(absPath, string(filepath.Separator), "-")
	projectDir := filepath.Join(home, ".claude", "projects", encoded)

	info, err := os.Stat(projectDir)
	if err != nil {
		return false
	}
	return info.IsDir()
}

package cli

import (
	"bufio"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// pick presents a list of options to the user and returns the selected one.
// Uses fzf if available, falls back to a numbered list.
func pick(prompt string, options []string) (string, error) {
	if len(options) == 0 {
		return "", fmt.Errorf("no options available")
	}
	if len(options) == 1 {
		return options[0], nil
	}

	if hasFzf() {
		return pickWithFzf(prompt, options)
	}
	return pickWithList(prompt, options)
}

func hasFzf() bool {
	_, err := exec.LookPath("fzf")
	return err == nil
}

func pickWithFzf(prompt string, options []string) (string, error) {
	cmd := exec.Command("fzf", "--prompt", prompt+" ", "--height", "~40%", "--reverse")
	cmd.Stdin = strings.NewReader(strings.Join(options, "\n"))
	cmd.Stderr = os.Stderr

	out, err := cmd.Output()
	if err != nil {
		return "", fmt.Errorf("selection cancelled")
	}
	return strings.TrimSpace(string(out)), nil
}

func pickWithList(prompt string, options []string) (string, error) {
	fmt.Println(prompt)
	for i, opt := range options {
		fmt.Printf("  [%d] %s\n", i+1, opt)
	}
	fmt.Print("Select: ")

	scanner := bufio.NewScanner(os.Stdin)
	if !scanner.Scan() {
		return "", fmt.Errorf("no input")
	}

	input := strings.TrimSpace(scanner.Text())

	// Try as number
	for i, opt := range options {
		if input == fmt.Sprintf("%d", i+1) {
			return opt, nil
		}
	}

	// Try as exact match
	for _, opt := range options {
		if opt == input {
			return opt, nil
		}
	}

	return "", fmt.Errorf("invalid selection: %s", input)
}

package internal

import (
	"os"
	"path/filepath"
	"strings"
)

const workspaceMarker = ".tws-workspace"

// DetectWorkspaceRoot checks if cwd is inside an existing workspace.
// Returns the workspace root or empty string.
func DetectWorkspaceRoot(cwd string, cfg Config) string {
	// Tier 1: Walk up looking for .tws-workspace marker
	dir := cwd
	for {
		if _, err := os.Stat(filepath.Join(dir, workspaceMarker)); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			break
		}
		dir = parent
	}

	// Tier 2: Check if cwd is inside any configured workspace path
	for _, ws := range cfg.Workspaces {
		absWs, err := filepath.Abs(ws)
		if err != nil {
			continue
		}
		absCwd, err := filepath.Abs(cwd)
		if err != nil {
			continue
		}
		if strings.HasPrefix(absCwd, absWs+string(filepath.Separator)) || absCwd == absWs {
			return absWs
		}
	}

	// Tier 3: Check if cwd is inside ~/tws
	home, _ := os.UserHomeDir()
	globalDefault := filepath.Join(home, "tws")
	absCwd, _ := filepath.Abs(cwd)
	if strings.HasPrefix(absCwd, globalDefault+string(filepath.Separator)) || absCwd == globalDefault {
		return globalDefault
	}

	return ""
}

// resolveTwsRoot contains the resolution logic with injectable dependencies.
func resolveTwsRoot(envRoot string, cwd string, repoRoot string, repoErr error, cfg Config) string {
	// 0. TWS_ROOT env var — always wins
	if envRoot != "" {
		return envRoot
	}

	// 1. Already inside a workspace? Return that root.
	if wsRoot := DetectWorkspaceRoot(cwd, cfg); wsRoot != "" {
		return wsRoot
	}

	// 2. Global config keyed by repo path
	if repoErr == nil {
		if ws, ok := cfg.Workspaces[repoRoot]; ok {
			return ws
		}

		// 3. Repo-relative sibling: ../<repo-name>.tws/
		repoName := filepath.Base(repoRoot)
		return filepath.Join(filepath.Dir(repoRoot), repoName+".tws")
	}

	// 4. Global fallback
	home, _ := os.UserHomeDir()
	return filepath.Join(home, "tws")
}

func TwsRoot() string {
	repoRoot, repoErr := MainRepoRoot()
	cfg := LoadConfig()
	cwd, _ := os.Getwd()
	return resolveTwsRoot(os.Getenv("TWS_ROOT"), cwd, repoRoot, repoErr, cfg)
}

func FeaturePath(feature string) string {
	return filepath.Join(TwsRoot(), feature)
}

func WorktreePath(feature, branch string) string {
	return filepath.Join(FeaturePath(feature), "worktrees", branch)
}

// ListFeatures returns the names of all feature directories in the workspace.
func ListFeatures() []string {
	wsRoot := TwsRoot()
	entries, err := os.ReadDir(wsRoot)
	if err != nil {
		return nil
	}
	var features []string
	for _, e := range entries {
		if e.IsDir() && e.Name() != ".tws-workspace" {
			features = append(features, e.Name())
		}
	}
	return features
}

// ListBranches returns the branch names for a feature from stack.yaml,
// or from the worktrees directory if no stack exists.
func ListBranches(feature string) []string {
	featurePath := FeaturePath(feature)
	stack, err := LoadStack(featurePath)
	if err == nil && len(stack.Branches) > 0 {
		var names []string
		for _, e := range stack.Branches {
			names = append(names, e.Name)
		}
		return names
	}

	// Fallback: list worktree directories
	wtDir := filepath.Join(featurePath, "worktrees")
	entries, err := os.ReadDir(wtDir)
	if err != nil {
		return nil
	}
	var names []string
	for _, e := range entries {
		if e.IsDir() {
			names = append(names, e.Name())
		}
	}
	return names
}
